  // @Output() \u10E1\u10D8\u10DC\u10E2\u10D0\u10E5\u10E1\u10D8\u10E1 \u10D5\u10D0\u10E0\u10D8\u10D0\u10DC\u10E2\u10D4\u10D1\u10D8:
  
